sql:
SELECT MIN(condition_id)
FROM conditions
WHERE condition_name = 'Good';

SELECT DISTINCT PV.vehicle_id
FROM promotion_vehicles AS PV
JOIN conditions AS C ON PV.promotion_id = C.condition_id;

SELECT promotion_id, COUNT(vehicle_id) AS vehicle_count
FROM promotion_vehicles
GROUP BY promotion_id;

SELECT promotion_id, COUNT(vehicle_id) AS total_vehicles
FROM promotion_vehicles
GROUP BY promotion_id;

SELECT pv.promotion_id, c.condition_id, c.condition_name
FROM promotion_vehicles pv
LEFT JOIN conditions c ON pv.promotion_id = c.condition_id;

SELECT promotion_id 
FROM promotion_vehicles 
WHERE vehicle_id = 0;

SELECT pv.vehicle_id
FROM promotion_vehicles pv
WHERE pv.promotion_id IS NOT NULL;

SELECT condition_id, condition_name
FROM conditions
WHERE condition_id = 2022;

SELECT COUNT(*) AS total_entries
FROM conditions
WHERE condition_name = 'Excellent' OR condition_id = 1;

SELECT pv.vehicle_id, COUNT(pv.promotion_id) AS number_of_promotions
FROM promotion_vehicles AS pv
GROUP BY pv.vehicle_id;

SELECT DISTINCT c.condition_name
FROM conditions c
JOIN promotion_vehicles p ON c.condition_id = p.promotion_id;

SELECT promotion_id, COUNT(vehicle_id) 
FROM promotion_vehicles 
GROUP BY promotion_id;

SELECT promotion_id, vehicle_id, 1 AS constant_column
FROM promotion_vehicles
ORDER BY promotion_id ASC;
